// Pure helpers for API reference coverage: does every OpenAPI operation and
// every `@neon/sdk/raw` method have a home in the docs, and vice versa?
//
// Three surfaces are compared, all in operationId space (the OpenAPI spec is the
// stable identity; the SDK raw layer is a deterministic rename of it via
// toSdkMethodName):
//
//   - documented — operationIds the docs cover, from the committed manifest
//     content/docs/api-operation-ids.json (generated by generate-api-ref.mjs)
//   - sdkRaw     — @neon/sdk/raw operation exports (installed package)
//   - spec       — operationIds in the live OpenAPI document (live runs only)
//
// This module is framework-free and side-effect-free so it can be imported by
// the verifier script AND unit tested without touching the network or the SDK.

import { toSdkMethodName } from '../../src/utils/api-ref.mjs';

// `@neon/sdk/raw` re-exports client/config helpers alongside the generated
// operation functions. These are infrastructure, not OpenAPI operations, and
// must be excluded from coverage comparisons.
export const NON_OPERATION_RAW_EXPORTS = new Set([
  'createClient',
  'createConfig',
  'wrapRaw',
  'client',
]);

const METHODS = new Set(['get', 'post', 'put', 'patch', 'delete', 'options', 'head', 'trace']);

/** Collect every operationId from a (dereferenced or raw) OpenAPI document. */
export function operationIdsFromSpec(spec) {
  const ids = new Set();
  for (const pathItem of Object.values(spec?.paths ?? {})) {
    if (!pathItem || typeof pathItem !== 'object') continue;
    for (const [method, op] of Object.entries(pathItem)) {
      if (!METHODS.has(method.toLowerCase())) continue;
      if (op && typeof op === 'object' && op.operationId) ids.add(op.operationId);
    }
  }
  return ids;
}

/** Operation exports of `@neon/sdk/raw` (function exports minus infrastructure). */
export function sdkRawOperationNames(rawModule) {
  return new Set(
    Object.keys(rawModule).filter(
      (name) => typeof rawModule[name] === 'function' && !NON_OPERATION_RAW_EXPORTS.has(name)
    )
  );
}

/**
 * Compare documented operationIds, the SDK raw surface, and (optionally) the
 * live spec. All inputs are collections of names; `documentedOps` and `specOps`
 * are operationIds, `rawOps` are SDK raw method names.
 *
 * Returns four sorted arrays:
 *   - sdkNotDocumented   raw methods with no matching documented operation
 *   - documentedNotInSdk documented operations with no matching raw method
 *   - specNotDocumented  spec operations the docs manifest omits (live only)
 *   - specNotInSdk       spec operations with no matching raw method (live only)
 */
export function computeCoverage({ documentedOps, rawOps, specOps = null }) {
  const documented = new Set(documentedOps);
  const raw = new Set(rawOps);

  // Documented operations projected into SDK-method space for symmetric diffing.
  const documentedAsMethods = new Set([...documented].map((id) => toSdkMethodName(id)));

  const sdkNotDocumented = [...raw].filter((m) => !documentedAsMethods.has(m)).sort();
  const documentedNotInSdk = [...documented]
    .filter((id) => !raw.has(toSdkMethodName(id)))
    .sort();

  let specNotDocumented = null;
  let specNotInSdk = null;
  if (specOps) {
    const spec = new Set(specOps);
    specNotDocumented = [...spec].filter((id) => !documented.has(id)).sort();
    specNotInSdk = [...spec].filter((id) => !raw.has(toSdkMethodName(id))).sort();
  }

  return { sdkNotDocumented, documentedNotInSdk, specNotDocumented, specNotInSdk };
}
